"use client";

/**
 * FlowMascot — la mascotte di DoFlow come componente React riutilizzabile.
 *
 * Esempi:
 *   <FlowMascot />                          // idle: galleggia, blink, segue il cursore, glow
 *   <FlowMascot shy />                       // occhi chiusi (es. focus sul campo password)
 *   <FlowMascot size={120} followCursor={false} />
 *   <FlowMascot float={false} glow={false} blink={false} />  // statica
 *
 * Tipico uso con una password:
 *   const [shy, setShy] = useState(false);
 *   <FlowMascot shy={shy} />
 *   <input type="password" onFocus={() => setShy(true)} onBlur={() => setShy(false)} />
 */

import React, { useEffect, useId, useRef, useState } from "react";

export type FlowMascotProps = {
  /** Larghezza (numero = px, oppure qualsiasi valore CSS). Default 300. */
  size?: number | string;
  /** Sbatte le palpebre periodicamente. Default true. */
  blink?: boolean;
  /** Tiene gli occhi chiusi (sorrisetto timido). Sovrascrive blink. Default false. */
  shy?: boolean;
  /** Si inclina verso il cursore. Default true. */
  followCursor?: boolean;
  /** Galleggia + respira. Default true. */
  float?: boolean;
  /** Alone luminoso pulsante dietro la mascotte. Default true. */
  glow?: boolean;
  className?: string;
  style?: React.CSSProperties;
  "aria-label"?: string;
};

